    "title": "세무사 선정",
    "html": "<h3>&#49464;&#47924;&#49324; &#49440;&#51221; (&#51076;&#45824;&#52264; &#44228;&#50557; &#51649;&#54980;):</h3><h3>&#9702; &#44264;&#46304;&#53440;&#51076;: &#51076;&#45824;&#52264; &#44228;&#50557;&#49436;&#50640; &#46020;&#51109;&#51012; &#52237;&#51088;&#47560;&#51088; &#48148;&#47196; &#49440;&#51221;&#54644;&#50556; &#54633;&#45768;&#45796;.</h3><h3>&nbsp; &nbsp;&#9702; &#51060;&#50976;:</h3><h3>&nbsp; &nbsp; &nbsp; &nbsp;1. &#49324;&#50629;&#51088;&#46321;&#47197; &#45824;&#54665;: &#49464;&#47924;&#49324;&#44032; &#51080;&#50612;&#50556; &#49324;&#50629;&#51088;&#46321;&#47197;&#51613;&#51012; &#48148;&#47196; &#45244; &#49688; &#51080;&#44256;, &#49324;&#50629;&#51088;&#46321;&#47197;&#51613;&#51060; &#51080;&#50612;&#50556; &#45824;&#52636;(&#45797;&#53552;&#47200;, &#49888;&#48372;) &#49888;&#52397;&#44284; &#44033;&#51333; &#51109;&#48708; &#44228;&#50557;&#51060; &#44032;&#45733;&#54633;&#45768;&#45796;</h3><h3>&nbsp; &nbsp; &nbsp; &nbsp;2. &#48708;&#50857; &#52376;&#47532;: &#51064;&#53580;&#47532;&#50612; &#44228;&#50557;&#44552;, &#52968;&#49444;&#54021; &#48708;&#50857; &#46321; &#44060;&#50896; &#51456;&#48708; &#44284;&#51221;&#50640;&#49436; &#50416;&#45716; &#53360; &#46024;&#51012; &#44221;&#48708;&#47196; &#51064;&#51221;&#48155;&#51004;&#47140;&#47732; &#52488;&#44592;&#48512;&#53552; &#49464;&#47924;&#49324;&#51032; &#44032;&#51060;&#46300;&#44032; &#54596;&#50836;&#54633;&#45768;&#45796;. &quot;&#44060;&#50896; &#51204; &#51648;&#52636;&#46020; &#49548;&#44553;&#54644;&#49436; &#52376;&#47532;&#54644; &#51456;&#45796;&quot;&#45716; &#49464;&#47924;&#49324;&#47484; &#47564;&#45208;&#50556; &#54633;&#45768;&#45796;</h3><h3>&nbsp; &nbsp; &nbsp; &nbsp;3. &#45824;&#52636; &#49436;&#47448;: &#51008;&#54665;&#50640;&#49436; &#50836;&#44396;&#54616;&#45716; &#44033;&#51333; &#49548;&#46301; &#51613;&#48729; &#49436;&#47448;&#47484; &#49464;&#47924;&#49324;&#44032; &#52313;&#44200;&#51469;&#45768;&#45796; </h3><h2>&#51076;&#45824;&#52264; &#44228;&#50557; &#48143; &#54665;&#51221; </h2><p>&quot;&#53945;&#50557; &#54620; &#51460;&#51060; &#49688;&#52380;&#47564; &#50896;&#51012; &#50500;&#44788;&#51469;&#45768;&#45796;.&quot;</p><h3>1. &#44228;&#50557; &#51204; &#54596;&#49688; &#52404;&#53356;: &#50857;&#46020;&#48320;&#44221; &#48143; &#51109;&#50528;&#51064; &#49884;&#49444;</h3><ul><li>500&#13217;&#51032; &#48277;&#52825;:&nbsp;&#44148;&#47932; &#45236; &#51032;&#50896;(&#52824;&#44284;/&#54620;&#51032;&#50896; &#51228;&#50808;, &#44057;&#51008; &#51032;&#50896;&#45180;&#47532; &#54633;&#49328;) &#48148;&#45797;&#47732;&#51201; &#54633;&#44228;&#44032; 500&#13217; &#51060;&#49345;&#51060;&#47732; &#51109;&#50528;&#51064; &#54200;&#51032;&#49884;&#49444;(&#51109;&#50528;&#51064; &#54868;&#51109;&#49892;, &#49849;&#44053;&#44592;, &#51452;&#52264;&#51109; &#46321; 7&#51333;) &#51032;&#47924;&#44032; &#48156;&#49373;&#54633;&#45768;&#45796; [S</li><li>&#45824;&#52376;&#48277;:&nbsp;&#44228;&#50557; &#51204; &#48152;&#46300;&#49884; &#44148;&#52629;&#49324;&#47484; &#53685;&#54644; &#50857;&#46020;&#48320;&#44221; &#44032;&#45733; &#50668;&#48512;&#50752; &#48708;&#50857;&#51012; &#54869;&#51064;&#54644;&#50556; &#54633;&#45768;&#45796;.</li></ul><h3>2. &#54596;&#49688; &#53945;&#50557; &#49324;&#54637; (&#48373;&#49324;&#54644;&#49436; &#50416;&#49464;&#50836;) </h3><ol start=\"1\"><li>&#51064;&#54728;&#44032; &#52293;&#51076;:&nbsp;&quot;&#44148;&#52629;&#47932; &#50857;&#46020;&#48320;&#44221;(1&#51333; &#44540;&#49373;-&#51032;&#50896;) &#48143; &#51032;&#47308;&#44592;&#44288; &#44060;&#49444; &#51064;&#54728;&#44032; &#48520;&#54728; &#49884; &#48376; &#44228;&#50557;&#51008; &#47924;&#54952;&#47196; &#54616;&#47728;, &#44228;&#50557;&#44552; &#51204;&#50529;&#51012; &#51593;&#49884; &#48152;&#54872;&#54620;&#45796;.&quot;</li><li>&#46021;&#51216;&#44428;:&nbsp;&quot;&#51076;&#45824;&#51064;&#51008; &#48376; &#44148;&#47932; &#45236; &#46041;&#51333; &#48143; &#50976;&#44288; &#51652;&#47308;&#44284;&#47785;(&#51221;&#54805;, &#53685;&#51613;, &#51116;&#54876;, &#49888;&#44221;&#50808;&#44284; &#46321;)&#51032; &#52628;&#44032; &#51077;&#51216;&#51012; &#51228;&#54620;&#54620;&#45796;.&quot;</li><li>&#47116;&#53944;&#54532;&#47532;:&nbsp;&quot;&#51064;&#53580;&#47532;&#50612; &#44277;&#49324; &#44592;&#44036; &#48143; &#44060;&#50896; &#51456;&#48708;&#47484; &#50948;&#54644; O&#44060;&#50900;&#51032; &#47116;&#53944;&#54532;&#47532;&#47484; &#51228;&#44277;&#54616;&#47728;, &#47116;&#53944;&#54532;&#47532; &#49884;&#51089;&#51068;&#51008; &#51092;&#44552;&#51068;(&#46608;&#45716; &#44277;&#49324; &#49884;&#51089;&#51068;)&#47196; &#54620;&#45796;.&quot;</li><li>&#50896;&#49345;&#48373;&#44396;:&nbsp;&quot;&#50896;&#49345;&#48373;&#44396;&#51032; &#48276;&#50948;&#45716; &#51076;&#52264;&#51064;&#51060; &#49884;&#49444;&#54620; &#51064;&#53580;&#47532;&#50612; &#48143; &#49884;&#49444;&#47932;&#50640; &#54620;&#54616;&#47728;, &#51077;&#51452; &#45817;&#49884; &#49345;&#53468;(&#52380;&#51109; &#53581;&#49828; &#47560;&#44048; &#46321;)&#47484; &#44592;&#51456;&#51004;&#47196; &#54620;&#45796;.&quot; (&#52384;&#44144;&#48708; &#48516;&#51137; &#50696;&#48169;)</li><li>&#51076;&#45824;&#47308; &#51064;&#49345;:&nbsp;&quot;&#51116;&#44228;&#50557; &#49884; &#51076;&#45824;&#47308; &#51064;&#49345;&#51008; &#49345;&#44032;&#51076;&#45824;&#52264;&#48372;&#54840;&#48277; &#49345;&#54620;&#49440;(5%) &#51060;&#45236;&#50640;&#49436; &#54801;&#51032;&#54620;&#45796;.&quot;</li></ol>"
